import { useState, useEffect } from "react";
import {
  Box,
  Typography,
  TextField,
  Button,
  Paper,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Autocomplete,
  Chip,
} from "@mui/material";
import { Edit } from "@mui/icons-material";
import DeleteIcon from "@mui/icons-material/Delete";
import API from "../../api/axios";

export default function ProjectManagement() {
  const [search, setSearch] = useState("");
  const [data, setData] = useState([]);
  const [users, setUsers] = useState([]);

  const [editOpen, setEditOpen] = useState(false);
  const [editData, setEditData] = useState(null);

  const [assignOpen, setAssignOpen] = useState(false);
  const [selectedProject, setSelectedProject] = useState(null);
  const [selectedUsers, setSelectedUsers] = useState([]);

  // 🔄 FETCH
  const fetchProjects = async () => {
    const res = await API.get("projects/");
    setData(res.data);
  };

  const fetchUsers = async () => {
    try {
      const res = await API.get("users/");
      setUsers(res.data);
    } catch {
      setUsers([]);
    }
  };

  useEffect(() => {
    fetchProjects();
    fetchUsers();
  }, []);

  // ✏️ UPDATE
  const updateProject = async () => {
    await API.put(`projects/${editData.id}/`, editData);
    setEditOpen(false);
    fetchProjects();
  };

  // 🗑 DELETE
  const deleteProject = async (id) => {
    if (!window.confirm("Delete project?")) return;
    await API.delete(`projects/${id}/delete/`);
    fetchProjects();
  };

  // ➕ ASSIGN
  const assignUserToProject = async () => {
    await API.post("assign-user/", {
      project_id: selectedProject.id,
      user_ids: selectedUsers.map((u) => u.id),
    });

    setAssignOpen(false);
    setSelectedUsers([]);
    fetchProjects();
  };

  // ❌ REMOVE USER
  const removeUserFromProject = async (projectId, userId) => {
    await API.post("remove-user/", {
      project_id: projectId,
      user_id: userId,
    });

    fetchProjects();
  };

  return (
    <Box sx={{ p: 4, display: "flex", justifyContent: "center" }}>
      <Paper sx={{ width: "100%", maxWidth: 1200, p: 4, borderRadius: 4 }}>
        {/* HEADER */}
        <Typography variant="h5" fontWeight="bold" mb={3}>
          Project Management
        </Typography>

        {/* SEARCH */}
        <TextField
          fullWidth
          placeholder="Search..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          sx={{ mb: 3 }}
        />

        {/* TABLE */}
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>
                <b>Project</b>
              </TableCell>
              <TableCell>
                <b>Users</b>
              </TableCell>
              <TableCell>
                <b>Description</b>
              </TableCell>
              <TableCell>
                <b>Start</b>
              </TableCell>
              <TableCell>
                <b>End</b>
              </TableCell>
              <TableCell>
                <b>Actions</b>
              </TableCell>
            </TableRow>
          </TableHead>

          <TableBody>
            {data
              .filter((d) =>
                d.project_name?.toLowerCase().includes(search.toLowerCase()),
              )
              .map((row) => (
                <TableRow key={row.id}>
                  <TableCell>{row.project_name}</TableCell>

                  {/* ✅ USERS WITH CHIPS */}
                  <TableCell>
                    {Array.isArray(row.users) && row.users.length > 0
                      ? row.users.map((u) => (
                          <Chip
                            key={u.id}
                            label={u.username}
                            onDelete={() => {
                              if (window.confirm("Remove user?")) {
                                removeUserFromProject(row.id, u.id);
                              }
                            }}
                            sx={{ mr: 1, mb: 1 }}
                          />
                        ))
                      : "-"}
                  </TableCell>

                  <TableCell>{row.description}</TableCell>
                  <TableCell>{row.start}</TableCell>
                  <TableCell>{row.end}</TableCell>

                  {/* ACTIONS */}
                  <TableCell>
                    <IconButton
                      onClick={() => {
                        setEditData(row);
                        setEditOpen(true);
                      }}
                    >
                      <Edit />
                    </IconButton>

                    <IconButton
                      onClick={() => {
                        setSelectedProject(row);
                        setAssignOpen(true);
                      }}
                      sx={{ color: "#2e7d32" }}
                    >
                      ➕
                    </IconButton>

                    <IconButton onClick={() => deleteProject(row.id)}>
                      <DeleteIcon />
                    </IconButton>
                  </TableCell>
                </TableRow>
              ))}
          </TableBody>
        </Table>

        {/* EDIT MODAL */}
        <Dialog open={editOpen} onClose={() => setEditOpen(false)} fullWidth>
          <DialogTitle>Edit Project</DialogTitle>
          <DialogContent>
            <TextField
              fullWidth
              label="Project Name"
              value={editData?.project_name || ""}
              onChange={(e) =>
                setEditData({ ...editData, project_name: e.target.value })
              }
            />
          </DialogContent>
          <DialogActions>
            <Button onClick={() => setEditOpen(false)}>Cancel</Button>
            <Button onClick={updateProject}>Update</Button>
          </DialogActions>
        </Dialog>

        {/* ASSIGN USERS */}
        <Dialog
          open={assignOpen}
          onClose={() => setAssignOpen(false)}
          fullWidth
        >
          <DialogTitle>Assign Users</DialogTitle>

          <DialogContent>
            <Typography mb={2}>
              Project: <b>{selectedProject?.project_name}</b>
            </Typography>

            <Autocomplete
              multiple
              options={users}
              getOptionLabel={(option) => option.username}
              value={selectedUsers}
              onChange={(e, val) => setSelectedUsers(val)}
              renderTags={(value, getTagProps) =>
                value.map((option, index) => (
                  <Chip
                    label={option.username}
                    {...getTagProps({ index })}
                    key={option.id}
                  />
                ))
              }
              renderInput={(params) => (
                <TextField {...params} label="Select Users" />
              )}
            />
          </DialogContent>

          <DialogActions>
            <Button onClick={() => setAssignOpen(false)}>Cancel</Button>
            <Button onClick={assignUserToProject}>Assign</Button>
          </DialogActions>
        </Dialog>
      </Paper>
    </Box>
  );
}
